def _generate_response(self, understanding: Dict, pattern: Dict, emotion: str) -> str:
    """Generate natural language via the cognitive domain without fixed phrase lists."""
    from cognitive_language_domain import NarrativeStyle

    comp = understanding.get('comprehension', {})
    style_name = (comp.get('style') or 'conversational').upper()

    # be resilient to missing enum members
    try:
        style = getattr(NarrativeStyle, style_name)
    except Exception:
        style = NarrativeStyle.CONVERSATIONAL

    # Build the packet your CognitiveLanguageDomain expects.
    content = {
        'understanding': comp,
        'pattern': pattern or {},
        'emotion': emotion,
        'context': understanding.get('context', {}),
        'intent': understanding.get('intent', {'primary_intent': 'unknown'}),
        'semantic_frame': understanding.get('semantic_frame', {'type': 'action', 'roles': {}, 'confidence': 0.0}),
    }

    text = self.cognitive.generate_response(
        intent=content['intent'].get('primary_intent', 'unknown'),
        content=content,
        style=style
    )

    # fallback to the raw text we understood
    if not text or not isinstance(text, str) or not text.strip():
        text = comp.get('text') or ""

    return text.strip()
