def _generate_enhanced_response(self, understanding: Dict, pattern: Dict,
                                emotion: str, harvested_concepts: List[str]) -> str:
    """
    Synthesize a response from harvested facets + multimodal context.
    No canned phrases: we construct a linguistic seed dynamically.
    """
    from cognitive_language_domain import NarrativeStyle

    comp = understanding.get('comprehension', {})
    style_name = (comp.get('style') or 'conversational').upper()
    try:
        style = getattr(NarrativeStyle, style_name)
    except Exception:
        style = NarrativeStyle.CONVERSATIONAL

    # Gather a small, high-signal bundle from memory for the harvested concepts
    harvested_segments: List[str] = []
    for concept in harvested_concepts:
        try:
            mem = self.memory.recall(concept) or {}
            data = mem.get('data', {})
            facets = (data.get('facets') if isinstance(data, dict) else {}) or {}
            for f in facets.values():
                c = (f.get('content') or "").strip()
                if c:
                    harvested_segments.append(c)
        except Exception:
            continue

    # keep the densest few so we don't swamp the composer
    harvested_segments = sorted(harvested_segments, key=len, reverse=True)[:3]

    # Source text for synthesis
    original_text = comp.get('text') or ""
    synthesis_core = " ".join(harvested_segments) if harvested_segments else original_text

    multimodal_state = understanding.get('context', {}).get('multimodal_state', {})
    multimodal_score = multimodal_state.get('integration_score', 0.0)
    affect = multimodal_state.get('dominant_emotion', emotion)
    context_tags = list((pattern or {}).keys())

    # Build the cognition packet for the language domain (no prescriptive strings)
    content = {
        'seed': {
            'subject': 'system',
            'relation': 'interprets',
            'object': original_text if original_text else synthesis_core,
            'affect': affect,
            'coherence': float(multimodal_score),
            'tags': context_tags,
            'concepts': harvested_concepts
        },
        'synthesis': synthesis_core,
        'emotion': affect,
        'pattern': pattern or {},
        'intent': understanding.get('intent', {'primary_intent': 'reflect'}),
        'semantic_frame': understanding.get('semantic_frame', {'type': 'action', 'roles': {}, 'confidence': 0.0}),
        'context': understanding.get('context', {})
    }

    text = self.cognitive.generate_response(
        intent=content['intent'].get('primary_intent', 'reflect'),
        content=content,
        style=style
    )

    if not text or not isinstance(text, str) or not text.strip():
        text = synthesis_core if synthesis_core else ""

    return text.strip()
